export function getQuestoesCursoByPeriodo(periodoId) {
  if (!periodoId) return questoesSimuladoCurso;
  return questoesSimuladoCurso.filter((q) => q.periodo === String(periodoId));
}

export function getQuestaoCursoById(id) {
  return questoesSimuladoCurso.find((q) => q.id === id) || null;
}
